const p = require('/app/nocobase/storage/node_modules/pinyin-pro');
const projName = $context.data.project_name;
let initials = '';
if (projName) {
  initials = p.pinyin(projName, { pattern: 'first', toneType: 'none' }).replace(/ /g, '').toUpperCase();
  if (initials.length > 2) initials = initials.substring(0, 2);
}
if (!initials && $context.data.pinyin_initials) {
  return $context.data.pinyin_initials;
}
return initials;

var date = $context.data.log_date ? new Date($context.data.log_date) : new Date();
var datePart = String(date.getFullYear()) + String(date.getMonth() + 1).padStart(2, '0') + String(date.getDate()).padStart(2, '0');
var proj = $context.data.project_id_id;
var projId = proj ? proj.id : ($context.data.project_id || '');
var p = require('/app/nocobase/storage/node_modules/pinyin-pro');
var projName = proj ? proj.project_name : '';
var initials = 'XX';
if (projName) {
  initials = p.pinyin(projName, { pattern: 'first', toneType: 'none' }).replace(/ /g, '').toUpperCase().substring(0, 2);
}
var http = require('http');
var serial = await new Promise(function(resolve) {
  http.get('http://127.0.0.1:13000/api/__pd__/next-serial?prefix=SG&date=' + datePart + '&project_id=' + projId, function(res) {
    var body = '';
    res.on('data', function(c) { body += c; });
    res.on('end', function() {
      try { var r = JSON.parse(body); resolve(r.data && r.data.seq ? String(r.data.seq).padStart(3, '0') : null); } catch(e) { resolve(null); }
    });
  }).on('error', function() { resolve(null); });
});
if (!serial) serial = '001';
return 'SG-' + initials + datePart + serial;

var date = $context.data.entry_date ? new Date($context.data.entry_date) : new Date();
var datePart = String(date.getFullYear()) + String(date.getMonth() + 1).padStart(2, '0') + String(date.getDate()).padStart(2, '0');
var proj = $context.data.project_id_id;
var projId = proj ? proj.id : ($context.data.project_id || '');
var p = require('/app/nocobase/storage/node_modules/pinyin-pro');
var projName = proj ? proj.project_name : '';
var initials = 'XX';
if (projName) {
  initials = p.pinyin(projName, { pattern: 'first', toneType: 'none' }).replace(/ /g, '').toUpperCase().substring(0, 2);
}
var http = require('http');
var serial = await new Promise(function(resolve) {
  http.get('http://127.0.0.1:13000/api/__pd__/next-serial?prefix=SG&date=' + datePart + '&project_id=' + projId, function(res) {
    var body = '';
    res.on('data', function(c) { body += c; });
    res.on('end', function() {
      try { var r = JSON.parse(body); resolve(r.data && r.data.seq ? String(r.data.seq).padStart(3, '0') : null); } catch(e) { resolve(null); }
    });
  }).on('error', function() { resolve(null); });
});
if (!serial) serial = '001';
return 'SG-' + initials + datePart + serial;

var queryResult = $jobsMapByNodeKey.pw0zbz0tant || {};
var entries = queryResult.data || [];
if (!Array.isArray(entries)) { var tmp = []; if (entries) tmp.push(entries); entries = tmp; }

var projects = {};
var projectKeys = [];
entries.forEach(function(e) {
  var pid = e.project_id;
  if (!pid) return;
  if (!projects[pid]) {
    projects[pid] = { projectId: pid, entries: [], workerSet: {}, weathers: {} };
    projectKeys.push(pid);
  }
  projects[pid].entries.push(e);
  if (e.reporter_id) projects[pid].workerSet[e.reporter_id] = true;
  if (e.weather) projects[pid].weathers[e.weather] = true;
});

var summaries = [];
var today = new Date().toISOString().slice(0, 10);
projectKeys.forEach(function(key) {
  var p = projects[key];
  var wKeys = [];
  for (var wk in p.weathers) { if (p.weathers.hasOwnProperty(wk)) wKeys.push(wk); }
  summaries.push({
    projectId: p.projectId,
    entryCount: p.entries.length,
    workerCount: Object.keys(p.workerSet).length,
    weather: wKeys.join(','),
    summaryDate: today
  });
});

var http = require('http');
var postData = JSON.stringify({ summaries: summaries });
var createResult = await new Promise(function(resolve) {
  var req = http.request({
    hostname: '127.0.0.1',
    port: 13000,
    path: '/api/__pd__/batch-create-logs',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(postData) }
  }, function(res) {
    var body = '';
    res.on('data', function(c) { body += c; });
    res.on('end', function() {
      try { resolve(JSON.parse(body)); } catch(e) { resolve({ code: -1, msg: e.message }); }
    });
  });
  req.on('error', function(err) { resolve({ code: -1, msg: err.message }); });
  req.write(postData);
  req.end();
});

return { summaries: summaries, totalEntries: entries.length, createResult: createResult };

var proj = $context.data.project_id_id;
if (!proj || !proj.location_lat || !proj.location_lon) return {};
var http = require('http');
var weather = await new Promise(function(resolve) {
  http.get('http://127.0.0.1:13000/api/__pd__/weather-qw?lat=' + proj.location_lat + '&lng=' + proj.location_lon, function(res) {
    var body = '';
    res.on('data', function(c) { body += c; });
    res.on('end', function() {
      try { resolve(JSON.parse(body)); } catch(e) { resolve(null); }
    });
  }).on('error', function() { resolve(null); });
});
if (weather && weather.data) {
  return { weather: weather.data.weather + ' ' + (weather.data.temperature || '') + 'C ' + (weather.data.windDirection || '') };
}
return {};
